let baseDuration = datetime({BaselineRange:endISO}) - datetime({BaselineRange:startISO});
let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let baseStart = spikeStart - baseDuration;
{Table}
| where Timestamp >= baseStart and Timestamp <= spikeEnd
| summarize Rows = count() by Day = bin(Timestamp, 1d)
| order by Day asc

let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let baseDuration = datetime({BaselineRange:endISO}) - datetime({BaselineRange:startISO});
let baseStart = spikeStart - baseDuration;
let baseEnd = spikeStart;
let spikeDays = toscalar(print d = (spikeEnd - spikeStart) / 1d);
let baseDays = toscalar(print d = baseDuration / 1d);
let spike =
    {Table}
    | where Timestamp >= spikeStart and Timestamp <= spikeEnd
    | summarize SpikePerDay = todouble(count()) / spikeDays by ActionType;
let base =
    {Table}
    | where Timestamp >= baseStart and Timestamp < baseEnd
    | summarize BasePerDay = todouble(count()) / baseDays by ActionType;
spike
| join kind=fullouter base on ActionType
| extend ActionType = coalesce(ActionType, ActionType1), SpikePerDay = coalesce(SpikePerDay, real(0)), BasePerDay = coalesce(BasePerDay, real(0))
| extend Delta = SpikePerDay - BasePerDay
| extend Ratio = iff(BasePerDay > 0, round(SpikePerDay / BasePerDay, 3), real(null))
| project ActionType, BasePerDay = round(BasePerDay, 3), SpikePerDay = round(SpikePerDay, 3), Delta = round(Delta, 3), Ratio
| order by Delta desc

let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let baseDuration = datetime({BaselineRange:endISO}) - datetime({BaselineRange:startISO});
let baseStart = spikeStart - baseDuration;
let baseEnd = spikeStart;
let spikeDays = toscalar(print d = (spikeEnd - spikeStart) / 1d);
let baseDays = toscalar(print d = baseDuration / 1d);
let spike =
    {Table}
    | where Timestamp >= spikeStart and Timestamp <= spikeEnd
    | summarize SpikePerDay = todouble(count()) / spikeDays by ActionType;
let base =
    {Table}
    | where Timestamp >= baseStart and Timestamp < baseEnd
    | summarize BasePerDay = todouble(count()) / baseDays by ActionType;
let combined = spike
    | join kind=fullouter base on ActionType
    | extend ActionType = coalesce(ActionType, ActionType1), SpikePerDay = coalesce(SpikePerDay, real(0)), BasePerDay = coalesce(BasePerDay, real(0))
    | extend Delta = SpikePerDay - BasePerDay
    | order by Delta desc
    | take 15
    | project ActionType, BasePerDay = round(BasePerDay, 3), SpikePerDay = round(SpikePerDay, 3);
union
    (combined | project ActionType, Series = '1 Baseline per day', Value = BasePerDay),
    (combined | project ActionType, Series = '2 Spike per day', Value = SpikePerDay)
| order by ActionType asc, Series asc

let spikeStart = datetime({SpikeRange:startISO});
let spikeEnd = datetime({SpikeRange:endISO});
let baseDuration = datetime({BaselineRange:endISO}) - datetime({BaselineRange:startISO});
let baseStart = spikeStart - baseDuration;
let baseEnd = spikeStart;
let spikeDays = toscalar(print d = (spikeEnd - spikeStart) / 1d);
let baseDays = toscalar(print d = baseDuration / 1d);
let spike =
    {Table}
    | where Timestamp >= spikeStart and Timestamp <= spikeEnd
    | extend ChildName = column_ifexists('FileName', '')
    | summarize Spike = todouble(count()) / spikeDays by InitiatingProcessFileName, ChildName;
let base =
    {Table}
    | where Timestamp >= baseStart and Timestamp < baseEnd
    | extend ChildName = column_ifexists('FileName', '')
    | summarize Baseline = todouble(count()) / baseDays by InitiatingProcessFileName, ChildName;
spike
| join kind=fullouter base on InitiatingProcessFileName, ChildName
| extend InitiatingProcessFileName = coalesce(InitiatingProcessFileName, InitiatingProcessFileName1), ChildName = coalesce(ChildName, ChildName1), Spike = coalesce(Spike, real(0)), Baseline = coalesce(Baseline, real(0))
| extend Delta = Spike - Baseline
| where Delta > toreal('{Threshold}')
| project ParentFileName = InitiatingProcessFileName, ChildName, Baseline = round(Baseline, 3), Spike = round(Spike, 3), Delta = round(Delta, 3)
| order by Delta desc
| take 50
